package com.example.cordaimport android.os.Bundleimport android.view.WindowManagerimport androidx.activity.ComponentActivityimport androidx.activity.SystemBarStyleimport androidx.activity.compose.setContentimport androidx.activity.enableEdgeToEdgeimport androidx.compose.runtime.LaunchedEffectimport androidx.compose.runtime.getValueimport androidx.compose.ui.graphics.toArgbimport androidx.lifecycle.compose.collectAsStateWithLifecycleimport com.example.corda.data.SettingsManagerimport com.example.corda.ui.CordaAppimport com.example.corda.ui.screen.settings.SettingsViewModelimport com.example.corda.ui.theme.CordaThemeimport com.example.corda.ui.theme.ProvideAppLocaleimport com.example.corda.ui.theme.applyWindowThemeimport com.example.corda.ui.theme.backgroundDarkimport com.example.corda.ui.theme.backgroundLightimport kotlinx.coroutines.flow.firstimport kotlinx.coroutines.runBlockingimport java.util.Localeclass MainActivity : ComponentActivity() {    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        val settingsManager = SettingsManager(applicationContext)        val initialDark = runBlocking { settingsManager.isDarkMode.first() }        val settingsViewModel = SettingsViewModel(            settingsManager = settingsManager,            initialDarkMode = initialDark,            )        applyWindowTheme(this, initialDark)        enableEdgeToEdge(            statusBarStyle = SystemBarStyle.auto(                lightScrim = backgroundLight.toArgb(),                darkScrim = backgroundDark.toArgb(),                ),            navigationBarStyle = SystemBarStyle.auto(                lightScrim = android.graphics.Color.TRANSPARENT,                darkScrim = android.graphics.Color.TRANSPARENT,                ),            )        setContent {            val isDark by settingsViewModel.isDarkMode.collectAsStateWithLifecycle()            val keepFocus by settingsViewModel.keepFocus.collectAsStateWithLifecycle()            val languageTag by settingsViewModel.language.collectAsStateWithLifecycle()            LaunchedEffect(keepFocus) {                if (keepFocus) {                    window.addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)                } else {                    window.clearFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)                }            }            LaunchedEffect(languageTag) {                Locale.setDefault(Locale.forLanguageTag(languageTag))            }            ProvideAppLocale(languageTag = languageTag) {                CordaTheme(darkTheme = isDark) {                    CordaApp(settingsViewModel = settingsViewModel)                }            }        }    }}